using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int t, n, m, x, y, d[100010], ans[100010], cnt;
vector<int> v[100010];
priority_queue<int> q;
signed main(void)
{
	cin >> t;
	while (t -- )
	{
		cin >> n >> m;
		cnt = 0;
		for (int i = 1; i <= n; i ++)
        {
            v[i].clear();
            d[i] = 0;
        }
		for (int i = 1; i <= m; i ++)
		{
			cin >> x >> y;
			v[y].push_back(x);
            d[x] ++;
		}
		for (int i = 1; i <= n; i ++)
		{
			if (!d[i])q.push(i);
		}
		while (q.size())
		{
			int now = q.top();
			q.pop();
            ans[++cnt] = now;
			for (auto u : v[now])
			{
				d[u] --;
				if (!d[u])q.push(u);
			}
		}
		if (cnt < n)
		{
			puts("Impossible!");
			continue;
		}
		for (int i = cnt; i >= 1; i --)
        {
            cout << ans[i] << " ";
        }
		cout << '\n';
	}
	return false;
}
